const items = $input.all();
const results = [];
for (const item of items) {
  const c = item.json;
  if (c.email && c.email.trim() !== '') {
    results.push({ json: c });
  }
}
return results.length > 0 ? results : [{ json: { _skip: true, reason: 'no_valid_emails' } }];

const FONT = "-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif";
const GREEN_DARK = '#166534';
const GREEN_MID = '#15803d';
const GOLD = '#C5A55A';
const DARK = '#1a1a2e';

const results = [];
for (const item of $input.all()) {
  const c = item.json;
  if (c._skip) continue;

  const name = c.first_name || 'there';
  const subject = `Spring is here, ${name}! Time to wake up your lawn`;

  const html_body = `<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><style>body,table,td,a{-webkit-text-size-adjust:100%;-ms-text-size-adjust:100%}table,td{mso-table-lspace:0pt;mso-table-rspace:0pt}body{margin:0;padding:0;width:100%!important;background-color:#f4f4f4}</style></head><body style="margin:0;padding:0;background-color:#f4f4f4;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="background-color:#f4f4f4;"><tr><td align="center" style="padding:20px 0;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="600" style="max-width:600px;background-color:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06);">` +

  `<tr><td style="background:linear-gradient(135deg,${GREEN_DARK} 0%,${GREEN_MID} 100%);"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%"><tr><td style="padding:16px 24px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%"><tr><td style="font-family:${FONT};font-size:18px;font-weight:700;color:#ffffff;">TotalGuard Yard Care</td><td align="right" style="font-family:${FONT};font-size:14px;color:#ffffff;"><a href="tel:+16085356057" style="color:#ffffff;text-decoration:none;font-weight:600;">(608) 535-6057</a></td></tr></table></td></tr><tr><td align="center" style="padding:0 24px 14px;font-family:${FONT};font-size:13px;color:${GOLD};letter-spacing:1.5px;text-transform:uppercase;font-weight:600;">Madison's Most Trusted Yard Care</td></tr></table></td></tr>` +

  `<tr><td style="background:linear-gradient(135deg,${GREEN_DARK} 0%,${GREEN_MID} 50%,${GREEN_DARK} 100%);"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%"><tr><td align="center" style="padding:48px 32px 16px;"><h1 style="margin:0;font-family:${FONT};font-size:28px;font-weight:800;color:#ffffff;">Spring Is Here, ${name}!</h1></td></tr><tr><td align="center" style="padding:8px 40px 48px;"><p style="margin:0;font-family:${FONT};font-size:16px;color:${GOLD};font-weight:500;">Time to wake up your lawn after a long Wisconsin winter.</p></td></tr></table></td></tr>` +

  `<tr><td style="padding:32px 32px 16px;"><div style="font-family:${FONT};font-size:15px;color:#333;line-height:1.7;"><p style="margin:0 0 16px;">Hi ${name},</p><p style="margin:0 0 16px;">Winter is finally behind us, and your lawn is ready for some attention. Here are the spring services that will set your yard up for a beautiful season:</p><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="margin:0 0 16px;"><tr><td style="padding:12px 16px;background-color:#f0f8f0;border-radius:6px;"><strong style="color:${GREEN_DARK};">&#127793; Spring Cleanup</strong><br><span style="font-size:14px;color:#555;">Full debris removal, bed edging, first mow of the season</span></td></tr><tr><td style="padding:4px;"></td></tr><tr><td style="padding:12px 16px;background-color:#f0f8f0;border-radius:6px;"><strong style="color:${GREEN_DARK};">&#127807; Fertilization Program</strong><br><span style="font-size:14px;color:#555;">Custom 5-step program to green up your lawn fast</span></td></tr><tr><td style="padding:4px;"></td></tr><tr><td style="padding:12px 16px;background-color:#f0f8f0;border-radius:6px;"><strong style="color:${GREEN_DARK};">&#9749; Aeration</strong><br><span style="font-size:14px;color:#555;">Break up compacted soil so roots can breathe and grow</span></td></tr></table><p style="margin:0;">Spots fill up fast in spring. Book now to lock in your preferred date.</p></div></td></tr>` +

  `<tr><td style="padding:0 32px 32px;" align="center"><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="width:100%;"><tr><td align="center" style="border-radius:6px;background-color:${GREEN_DARK};"><a href="https://tgyardcare.com/contact?utm_source=email&utm_medium=nurture&utm_campaign=spring-2026" target="_blank" style="display:block;padding:16px 32px;font-family:${FONT};font-size:16px;font-weight:700;color:#ffffff;text-decoration:none;border-radius:6px;text-align:center;">Schedule My Spring Cleanup &#8594;</a></td></tr></table></td></tr>` +

  `<tr><td style="padding:0 32px 24px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="background-color:${GREEN_DARK};border-radius:6px;"><tr><td align="center" style="padding:14px 16px;font-family:${FONT};font-size:12px;color:#ffffff;line-height:2;">&#10003; Licensed &amp; Insured&nbsp;&bull;&nbsp;&#10003; 4.9&#9733; Rating&nbsp;&bull;&nbsp;&#10003; 500+ Properties&nbsp;&bull;&nbsp;&#10003; 100% Satisfaction Guarantee</td></tr></table></td></tr>` +

  `<tr><td style="background-color:${DARK};border-radius:0 0 8px 8px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%"><tr><td align="center" style="padding:32px 32px 8px;"><p style="margin:0;font-family:${FONT};font-size:18px;font-weight:700;color:#ffffff;">TotalGuard Yard Care</p></td></tr><tr><td align="center" style="padding:4px 32px;"><p style="margin:0;font-family:${FONT};font-size:13px;color:#999;line-height:1.6;">7610 Welton Dr, Madison, WI 53711&nbsp;|&nbsp;<a href="tel:+16085356057" style="color:${GOLD};text-decoration:none;">(608) 535-6057</a>&nbsp;|&nbsp;<a href="mailto:totalguardllc@gmail.com" style="color:${GOLD};text-decoration:none;">totalguardllc@gmail.com</a></p></td></tr><tr><td align="center" style="padding:8px 32px 32px;"><p style="margin:0;font-family:${FONT};font-size:11px;color:#666;line-height:1.6;">You're receiving this because you're a TotalGuard customer.<br><a href="https://tgyardcare.com/unsubscribe" style="color:#999;text-decoration:underline;">Unsubscribe</a></p></td></tr></table></td></tr>` +

  `</table></td></tr></table></body></html>`;

  results.push({
    json: {
      to_email: c.email,
      subject: subject,
      html_body: html_body,
      workflow_name: 'TG-14',
      email_type: 'spring_campaign'
    }
  });
}

return results.length > 0 ? results : [{ json: { _skip: true, reason: 'no_emails_to_send' } }];

